"""
Utility functions for countdown.py
"""

import re
import json
import itertools
import numpy as np
import torch


def generate_successors(state):
    """
    Generates all possible successor states from a given state by combining any two numbers
    using basic arithmetic operations.

    Parameters:
        state (Tuple[int]): The current state as a tuple of numbers.

    Returns:
        List[Dict]: A list of successor nodes with 'state' and 'operation' keys.
    """
    successors = []
    nums = list(state)
    # iterate over all unique combinations of numbers from set
    unique_combinations = []
    for a, b in itertools.combinations(nums, 2):
        if sorted([a, b]) not in unique_combinations:
            unique_combinations.append(sorted([a, b]))

    for a, b in unique_combinations:
        nums_copy = nums.copy()
        nums_copy.remove(a)
        nums_copy.remove(b)
        remaining = nums_copy

        # List of possible operations (equal signs not added for simplicity)
        operations = [
            (a + b, [a, "+", b, "=", str(a + b)]),
            (a * b, [a, "*", b, "=", str(a * b)]),
        ]

        if a <= b:
            operations.append((b - a, [b, "-", a, "=", str(b - a)]))
            if a != 0 and b % a == 0:
                operations.append((b // a, [b, "/", a, "=", str(b // a)]))
        else:
            operations.append((a - b, [a, "-", b, "=", str(a - b)]))
            if b != 0 and a % b == 0:
                operations.append((a // b, [a, "/", b, "=", str(a // b)]))

        # Add new successors
        for result, operation in operations:
            new_state = tuple(sorted(remaining + [result]))
            successors.append({"state": new_state, "operation": operation})

    # prune operations that use similar numbers and result in the same state
    duplicates_to_remove = set()
    operator_order = {"+": 1, "*": 2, "-": 3, "/": 4}
    groups = {}
    for i, successor in enumerate(successors):
        a = int(successor["operation"][0])
        b = int(successor["operation"][2])
        key = (successor["state"], frozenset([a, b]))
        if key not in groups:
            groups[key] = []
        groups[key].append(i)
    for indices in groups.values():
        if len(indices) > 1:
            selected = min(
                indices,
                key=lambda x: operator_order.get(successors[x]["operation"][1], 5),
            )
            for idx in indices:
                if idx != selected:
                    duplicates_to_remove.add(idx)
    duplicates = list(duplicates_to_remove)

    # remove duplicates
    successors = [state for i, state in enumerate(successors) if i not in duplicates]

    # convert operations to strings
    for successor in successors:
        successor["operation"] = "".join(
            [str(element) for element in successor["operation"]]
        )

    return successors


def generate_predecessors(state):
    """Generate all possible predecessor states that could lead to the given state.

    Args:
        state (tuple): A tuple of integers representing the current state

    Returns:
        list: List of dictionaries containing predecessor states and the operations that led to current state
    """
    predecessors = []

    # For each number in the state
    for target in state:
        # Try all pairs of numbers that could combine to make this target
        for a in range(1, target + 1):
            for b in range(1, target + 1):
                # Get all possible operations between these numbers
                possible_ops = combine_nums(a, b)

                # Check if any operation results in our target
                for result, operation in possible_ops:
                    if result == target:
                        # Create the predecessor state by removing target and adding a,b
                        pred_nums = list(state)
                        pred_nums.remove(target)
                        pred_nums.extend([a, b])
                        pred_state = tuple(sorted(pred_nums))

                        predecessors.append(
                            {"state": pred_state, "operation": operation}
                        )

    # Remove duplicates
    seen = set()
    unique_predecessors = []
    for pred in predecessors:
        key = (pred["state"], pred["operation"])
        if key not in seen:
            seen.add(key)
            unique_predecessors.append(pred)

    return unique_predecessors


def combine_nums(a, b):
    # Implicitly makes assumptions about the order of operations and valid operations
    a = int(a)
    b = int(b)
    possible = [[a + b, f"{a}+{b}={a + b}"], [a * b, f"{a}*{b}={a * b}"]]
    if a <= b:
        possible.append([b - a, f"{b}-{a}={b - a}"])
        if a != 0 and b % a == 0:
            possible.append([b // a, f"{b}/{a}={round(b // a, 0)}"])
    else:
        possible.append([a - b, f"{a}-{b}={a - b}"])
        if b != 0 and a % b == 0:
            possible.append([a // b, f"{a}/{b}={round(a // b, 0)}"])
    return possible


class CountdownNode:
    def __init__(self, idx, parent, nums, operations, heuristic=None, is_subgoal=False):
        self.nums = nums
        self.operations = operations
        self.heuristic = heuristic
        self.parent = parent
        self.idx = idx
        self.is_subgoal = is_subgoal

    def __lt__(self, other):
        return self.heuristic < other.heuristic


def compute_softmax(heuristics, temperature=1.0):
    heuristics = (
        -1 * torch.tensor(heuristics) / temperature + 1e-6
    )  # numerical stability
    probs = torch.nn.functional.softmax(heuristics, dim=0)
    return probs.tolist()


heuristics_dict = {"sum_difference": [], "product_difference": [], "max_minus_rest": []}


def combo_heuristic(nums, target):
    heuristics = np.array(
        [
            sum_difference(nums, target),
            product_difference(nums, target),
            max_minus_rest(nums, target),
        ]
    )
    heuristics_dict["sum_difference"].append(heuristics[0].item())
    heuristics_dict["product_difference"].append(heuristics[1].item())
    heuristics_dict["max_minus_rest"].append(heuristics[2].item())
    heuristics = heuristics / len(heuristics)
    if heuristics.min() == 0:
        return -2
    return sum(heuristics).item()


def baseline_detect_target(nums, target):
    if nums[0] == target:
        return -4
    return 1


# Heuristics functions
def baseline_heuristic(nums, target):
    return 1


def sum_difference(nums, target):
    return abs(sum(nums) - target)


def product_difference(nums, target):
    return abs(np.prod(np.array(nums)) - target)


def max_minus_rest(nums, target):
    return abs(2 * max(nums) - sum(nums) - target)


def sum_heuristic(nums, target):
    return sum([abs(num - target) for num in nums])


def mult_heuristic(nums, target):
    # get closer to factors of target
    # return sum([0 if (nums[i] == 0 or target % nums[i] == 0 or nums[i] % target == 0) else 1 for i in range(len(nums))])
    # softer version, with distance to factors
    factors = [i for i in range(2, target + 1) if target % i == 0]
    return sum([min(abs(num - factor) for factor in factors) for num in nums])


def ratio_heuristic(nums, target):
    return sum([abs(num / target - 1) for num in nums])


# prune functions
def great_prune(heuristic, target):
    # Simple pruning based on result magnitude
    return heuristic > target


def mult_prune(result, target):
    # Prune if result is not close to a factor of target
    factors = [i for i in range(1, target + 1) if target % i == 0]
    return all(abs(result - factor) > target for factor in factors)


def simple_rating(search_path):
    # Simple rating function based on number of operations
    nodes_explored = search_path.count("Exploring Operation") + 1
    return nodes_explored


def get_target_nums(search_path, mode=""):
    # Extracting the target and initial numbers from the first line
    first_line = search_path.strip().split("\n")[0]
    search_path = search_path.replace("<|endoftext|>", "")
    if mode == "dt":
        first_line = first_line.split("->")[1]
    target_nums_match = re.match(r"Current State: (\d+):\[(.*?)\]", first_line)
    if not target_nums_match:
        return "Invalid input: Cannot find the initial state in the first line."

    target, nums = (
        int(target_nums_match.group(1)),
        [int(n) for n in target_nums_match.group(2).split(", ")],
    )
    return target, nums


def parse_trajectory(search_path, mode="dt"):
    # Extracting the target and initial numbers from the first line
    first_line = search_path.strip().split("\n")[0]
    search_path = search_path.replace("<|endoftext|>", "")

    # if mode == "dt":
    #     first_line = first_line.split("->")[1]
    target_nums_match = re.match(r"Current State: (\d+):\[(.*?)\]", first_line)
    if not target_nums_match:
        return "Invalid input: Cannot find the initial state in the first line."

    target, nums = (
        int(target_nums_match.group(1)),
        [int(n) for n in target_nums_match.group(2).split(", ")],
    )

    # Extract the operations from the line that claims the goal is reached.
    goal_lines = re.finditer(r"\d+,\d+ equal: Goal Reached", search_path)
    goal_lines = list(goal_lines)
    if not goal_lines:
        return "No goal reached statement found."

    goal_line = goal_lines[0]
    # get the last operation line before the goal reached statement
    operations = re.findall(
        r"Exploring Operation: (.*?=\d+), Resulting Numbers: \[(.*?)\]",
        search_path[: goal_line.start()],
    )
    if not operations:
        return "No operations found leading to the goal."

    final_operation = operations[-1][0]
    try:
        predicted_result = int(final_operation.split("=")[1])
    except:
        print("couldnt parse last op", final_operation)
        return "Couldnt parse last op"
    if predicted_result != target:
        return "Invalid path: Final operation does not result in target."

    # get the last current state, operations before the goal reached statement, and extract the operations
    operation_list = re.findall(
        r"Current State: \d+:\[.*?\], Operations: \[(.*?)\]",
        search_path[: goal_line.start()],
    )[-1].split(", ")
    operation_list = [op.replace("'", "") for op in operation_list]
    operation_list += [final_operation]

    # Verify each operation and keep track of the numbers involved
    available_numbers = nums
    for operation in operation_list:
        # Verify the operation
        try:
            left, right = operation.split("=")
        except:
            return f"Could not split operation into lhs, rhs"
        try:
            if eval(left) != int(right):
                return f"Invalid operation: {operation}"
        except Exception as e:
            return f"Error in evaluating operation {operation}: {e}"
        # get the numbers involved
        used_numbers = re.findall(r"\d+", left)
        for n in used_numbers:
            if int(n) not in available_numbers:
                return f"Invalid operation: {operation}, number {n} not available in {available_numbers}"

        available_numbers = [n for n in available_numbers if n not in used_numbers]
        available_numbers.append(int(right))

    return "Valid path."


def metric_fn(search_path, mode="dt"):
    rating = parse_trajectory(search_path, mode=mode)
    if rating == "Valid path.":
        score = simple_rating(search_path)
        first_line = search_path.strip().split("\n")[0]
        if "->" in first_line:
            first_line = first_line.split("->")[1]
        target_nums_match = re.match(r"Current State: (\d+):\[(.*?)\]", first_line)
        target, nums = (
            int(target_nums_match.group(1)),
            [int(n) for n in target_nums_match.group(2).split(", ")],
        )
        if len(nums) == 2:
            # 2c2 x ops (4) = 4
            max_nodes = 4
        elif len(nums) == 3:
            # 3c2 x ops (4) x 2c2 x ops (4) = 48
            max_nodes = 48
        elif len(nums) == 4:
            # 4c2 x ops (4) x 3c2 x ops (4) x 2c2 x ops (4) = 1152
            max_nodes = 1152
        elif len(nums) == 5:
            # 5c2 x ops (4) x 4c2 x ops (4) x 3c2 x ops (4) x 2c2 x ops (4) = 46080
            max_nodes = 46080
        return (max(1.0 - score / max_nodes, 0.0), rating)
    return (0.0, rating)


"""
UTIL FUNCTIONS FOR PARSING TRAJECTORIES AND RETURNING SEARCH TREE OBJECT 
"""


class SearchTreeNode:
    def __init__(self, options, op, id):
        # what options remain at this node
        self.options = options
        # operation needed to get to this node from its parent
        self.op = op
        # id of each node. root node has id tuple([0])
        self.id = id


class SearchTree:
    """Current implementation works for correct trees"""

    def __init__(self):
        self.data = dict()
        self.target = -1
        # if no errors were made and the goal was reached correctly
        self.correctness = 0
        # if the "goal reached" statement is in the trajectory
        self.goal_reached = 0
        self.final_op_correct = 0

        self.num_total_nodes = 0
        self.correct_path = []
        self.num_nodes_in_correct_path = 0
        self.rating = 0
        # maximum number of nodes of full tree
        self.max_nodes = 0

        # characterizing failures
        self.errors = dict(
            {
                "arithmetic": dict(),
                "exploration": dict(),
                "formatting": dict(),
                "other": dict(),
            }
        )

    def print_tree(self, data, indent):
        if data == self.data:
            print(self.data)
            print(
                "Node 0:  Target: ",
                self.target,
                "Nums: ",
                self.data[0][0].options,
                "Correctness: ",
                self.correctness,
                "Rating: ",
                self.rating,
            )
            self.print_tree(data[0][1], 4)
        else:
            for key, node_and_dict in data.items():
                print(" " * indent + str(key), end=": ")  # print node id at this branch
                if bool(node_and_dict[1]):
                    print(
                        node_and_dict[0].options, node_and_dict[0].op
                    )  # Print information about node
                    self.print_tree(node_and_dict[1], indent + 4)
                else:
                    print(node_and_dict[0].options, node_and_dict[0].op)

    def parse_search_trajectory(self, search_path, mode="sft"):
        # Extracting the target and initial numbers from the first line
        first_line = search_path.strip().split("\n")[0]
        search_path = search_path.replace("<|endoftext|>", "")
        # trim to the first goal reached statement
        if "Goal Reached" in search_path:
            index = search_path.find("Goal Reached")
            search_path = search_path[: index + len("Goal Reached") + 1]

        target_nums_match = re.search(
            r"Current State: (\d+):\[(.*?)\]", first_line.replace("<|endoftext|>", "")
        )
        # target_nums_match = re.search(r"Current State: (\d+):\[(.*?)\]", first_line.replace("<|endoftext|>", ""))
